 "ektenia-podyaky": [
{ "t": "say", "role": "Диякон", "text": "Станьмо побожно! Прийнявши божественні, святі, пречисті, безсмертні, небесні і животворчі страшні Христові Тайни, достойно подякуймо Господу.", "solo": "priest" },
 { "t": "choir", "role": "Хор", "text": "Господи, помилуй." },
 { "t": "say", "role": "Диякон", "text": "Заступи, спаси, помилуй і збережи нас, Боже, Твоєю благодаттю.", "solo": "priest" },
 { "t": "choir", "role": "Хор", "text": "Господи, помилуй." },
 { "t": "say", "role": "Диякон", "text": "Дня всього звершеного, святого, мирного і безгрішного виблагавши, самих себе, і одне одного, і все життя наше Христу Богові віддамо.", "solo": "priest" },
 { "t": "choir", "role": "Хор", "text": "Тобі, Господи." }
 ],

 "ektenia-potriina-rannya": [
{ "t": "say", "role": "Диякон", "text": "Помилуй нас, Боже, з великої милості Твоєї, молимось Тобі, вислухай і помилуй.", "solo": "priest" },
 { "t": "choir", "role": "Хор", "text": "Господи, помилуй (тричі)." },
 { "t": "say", "role": "Диякон", "text": "Ще молимось за владику і отця нашого Блаженнійшого Митрополита Епіфанія{{архієрей}}, за братів наших священників, священномонахів і за все у Христі братство наше.", "solo": "priest" },
 { "t": "choir", "role": "Хор", "text": "Господи, помилуй (тричі)." },
 { "t": "say", "role": "Диякон", "text": "Ще молимось за Богом бережену Україну нашу, владу, військо та народ її, щоб ми тихе і мирне життя прожили у всякому благочесті і чистоті.", "solo": "priest" },
 { "t": "choir", "role": "Хор", "text": "Господи, помилуй (тричі)." },
 { "t": "say", "role": "Диякон", "text": "Ще молимось за спочилих ієрархів православних, за благочестивих і благовірних князів і гетьманів наших, за повік незабутніх фундаторів {{храм}}, і всіх раніше спочилих отців, братів і сестер наших, що тут і повсюди лежать, – православних.", "solo": "priest" },
 { "t": "choir", "role": "Хор", "text": "Господи, помилуй (тричі)." },
 { "t": "say", "role": "Диякон", "text": "Ще молимось за милість, життя, мир, здоров’я, спасіння, Боже завітання, прощення і відпущення гріхів рабів Божих – усіх {{парафіяни}}.", "solo": "priest" },
 { "t": "choir", "role": "Хор", "text": "Господи, помилуй (тричі)." },
 { "t": "say", "role": "Диякон", "text": "Ще молимось за тих, що дари приносять і добро діють у святому і всечесному храмі цьому; за тих, що трудяться, співають, і за всіх присутніх людей, що сподіваються від Тебе великої і багатої милості.", "solo": "priest" },
 { "t": "choir", "role": "Хор", "text": "Господи, помилуй (тричі)." }
 ],

